// Nodo "Preparar contexto": normaliza el webhook de Twilio y anonimiza al remitente.
// El número de teléfono NUNCA sigue viaje: solo su HMAC (mismo criterio que la tarjeta anónima).
// También captura timestamp y ubicación si están disponibles.
const crypto = require('crypto');

const b = $input.first().json.body || {};
const from = b.From || ''; // ej: "whatsapp:+549299XXXXXXX"

const secret = $env.HASH_SECRET || 'cambiar-este-secreto';
const hash = crypto.createHmac('sha256', secret).update(from).digest('hex').slice(0, 32);

const numMedia = Number(b.NumMedia || 0);
const mediaType = b.MediaContentType0 || '';
const hasMedia = numMedia > 0 && mediaType.startsWith('image');
// notas de voz de WhatsApp llegan como audio/ogg (opus); archivos: audio/mpeg, audio/mp4, audio/amr
const hasAudio = numMedia > 0 && mediaType.startsWith('audio');

// Capturar timestamp de Twilio (formato Unix)
const twilioTimestamp = b.Timestamp || Math.floor(Date.now() / 1000).toString();

// Capturar ubicación si el usuario la compartió
const latitud = b.Latitude ? parseFloat(b.Latitude) : null;
const longitud = b.Longitude ? parseFloat(b.Longitude) : null;

// Twilio exige Basic Auth (SID:token) para descargar el media adjunto
const twilioAuth = 'Basic ' + Buffer.from(`${$env.TWILIO_SID}:${$env.TWILIO_TOKEN}`).toString('base64');

return [{
  json: {
    hash,
    // Destinatario TRANSITORIO para responder por la API REST (el webhook ya devolvió
    // un ACK vacío; la respuesta real sale como mensaje nuevo). No se persiste nunca.
    to: from,
    fromBot: b.To || '',
    hasMedia,
    hasAudio,
    mediaUrl: (hasMedia || hasAudio) ? b.MediaUrl0 : null,
    mediaType,
    text: (b.Body || '').trim(),
    twilioAuth,
    twilioTimestamp,
    latitud,
    longitud,
  },
}];

// Nodo "Router": decide el camino mínimo. Toda la inteligencia conversacional vive
// en el Orquestador (LLM). Caminos: foto (tarjeta), adjuntar_foto (evidencia post-folio),
// audio, confirmación explícita de un resumen pendiente, u orquestador (todo el resto).
const ctx = $('Preparar contexto').first().json;
let session = $input.first().json.session || null;
const user = $input.first().json.user || { estado: 'activo', rechazos: 0 };
const t = (ctx.text || '').toLowerCase().trim();

const esConfirmacion = /^(ok|oka|okey|si|sí|dale|confirmo|listo|va|perfecto|correcto)\b/.test(t);

// Ventana de adjuntos post-folio: vigente hasta 10 min después de la última actividad.
// Cada foto adjuntada la renueva; cualquier texto/audio la cierra (empieza charla nueva).
const VENTANA_FOTOS_MIN = 10;
let ventanaFotos = false;
if (session && session.estado_flujo === 'awaiting_photos') {
  const upd = new Date(String(session.updated_at || '').replace(' ', 'T') + 'Z').getTime();
  ventanaFotos = Number.isFinite(upd) && (Date.now() - upd) / 60000 <= VENTANA_FOTOS_MIN;
  if (!ctx.hasMedia || !ventanaFotos) session = null; // texto/audio o ventana vencida: conversación nueva
}

let accion;
if (user.estado === 'bloqueado_temporal') {
  accion = 'bloqueado';                              // pausa anti-abuso: SIEMPRE se avisa, nunca silencio
} else if (ctx.hasMedia && ventanaFotos) {
  accion = 'adjuntar_foto';                          // evidencia para el folio recién registrado
} else if (ctx.hasMedia) {
  accion = 'foto';                                   // Flujo A: foto de la tarjeta de papel
} else if (ctx.hasAudio) {
  accion = 'audio';                                  // Flujo C: nota de voz → Whisper → orquestador
} else if (session && session.estado_flujo === 'awaiting_confirm' && esConfirmacion) {
  accion = 'confirmar';                              // el operario aprobó el resumen
} else {
  accion = 'orquestador';                            // TODO lo demás lo maneja el LLM
}

return [{ json: { ...ctx, session, user, accion } }];

// Nodo "Mensaje bloqueado": el usuario está en pausa anti-abuso. La regla de oro:
// NUNCA silencio — se le informa el estado y hasta cuándo, sin gastar una llamada al LLM.
const ctx = $input.first().json;
const u = ctx.user || {};

const tz = $env.GENERIC_TIMEZONE || 'America/Argentina/Buenos_Aires';
const hora = u.desbloqueado_en
  ? new Date(String(u.desbloqueado_en).replace(' ', 'T') + 'Z')
      .toLocaleTimeString('es-AR', { timeZone: tz, hour: '2-digit', minute: '2-digit', hour12: false })
  : null;

return [{ json: { persist: {
  reporter_hash: ctx.hash,
  reply: `🚫 La recepción de tus reportes está *pausada${hora ? ` hasta las ${hora}` : ' temporalmente'}* ` +
    'porque los últimos mensajes no parecían observaciones de seguridad.\n\n' +
    'El canal funciona correctamente — pasada la pausa podés volver a reportar con normalidad. ' +
    'Si creés que es un error, hablá con tu supervisor de HSE.',
} } }];

// Nodo "Armar respuesta": procesa la salida del LLM de visión (flujo foto), normaliza,
// detecta datos faltantes y arma la respuesta al operador + el payload de persistencia.
const ctx = $('Foto a base64').first().json;

const CATEGORIAS = {
  1: 'Reacciones de las Personas', 2: 'Posiciones de las Personas',
  3: 'Equipos de Protección Personal', 4: 'Herramientas y Equipos',
  5: 'Procedimientos', 6: 'Orden y Aseo', 7: 'Vehicular', 8: 'Ambiente',
  9: 'Productos Químicos', 10: 'Instalaciones', 11: 'Otros',
};
const TIPO = { inseguro: 'Acto Inseguro', seguro: 'Acto Seguro', no_audita: 'No Audita' };
const SEMAFORO = { rojo: '🔴 Crítica', amarillo: '🟡 Atención', verde: '🟢 Leve' };

// --- parsear la salida del LLM (tolerante a fences de markdown) ---
let datos = null;
try {
  const content = $input.first().json.choices[0].message.content;
  datos = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch (e) { /* LLM caído o respuesta inválida */ }

if (!datos) {
  return [{ json: { persist: {
    reporter_hash: ctx.hash,
    reply: '😕 No pude procesar tu mensaje en este momento. Probá de nuevo en unos minutos, o entregá la tarjeta en papel como siempre.',
  } } }];
}

// --- Legibilidad / confianza de la lectura de la foto ---
const legible = datos.tarjeta_legible !== false;
const confianza = typeof datos.confianza === 'number' ? datos.confianza : 1;
const dudas = Array.isArray(datos.dudas) ? datos.dudas.filter(Boolean) : [];

// Si la tarjeta está en blanco, no es una tarjeta o es ilegible: pedir reenvío o texto.
if (!legible || confianza < 0.35) {
  const motivo = dudas.length ? ` (${dudas.slice(0, 2).join('; ')})` : '';
  return [{ json: { persist: {
    reporter_hash: ctx.hash,
    session: null,
    reply: '📸 No pude leer bien la tarjeta' + motivo + '.\n\n' +
      'Probá sacarle una foto más nítida, con buena luz y sin sombras/suciedad, o *contame por texto* qué observaste y dónde.',
  } } }];
}

// --- ¿Ya había un borrador (ej. mandó el frente y ahora el dorso)? Consolidar ---
// Lo ya cargado gana; la foto nueva solo completa los campos vacíos.
const previos = (ctx.session && ctx.session.datos) || null;
if (previos) {
  for (const [k, v] of Object.entries(previos)) {
    if (k === '_historial') continue;
    if ((datos[k] == null || datos[k] === '') && v != null) datos[k] = v;
  }
  if (previos._historial) datos._historial = previos._historial;
}

// --- Integrar metadata de Twilio ---
if (ctx.twilioTimestamp) datos.timestamp_mensaje = ctx.twilioTimestamp;
if (ctx.latitud) datos.latitud = ctx.latitud;
if (ctx.longitud) datos.longitud = ctx.longitud;

// --- normalizar + prioridad determinística (el semáforo no se delega al LLM) ---
datos.tipo = ['inseguro', 'seguro', 'no_audita'].includes(datos.tipo) ? datos.tipo : 'inseguro';
datos.severidad = Math.min(4, Math.max(1, Number(datos.severidad) || 1));
datos.prioridad = datos.tipo === 'seguro' ? 'verde'
  : datos.severidad >= 3 ? 'rojo'
  : datos.severidad === 2 ? 'amarillo' : 'verde';
const cat = Number(datos.categoria);
datos.categoria = cat >= 1 && cat <= 11 ? cat : null;
datos.fecha_obs = datos.fecha_obs || datos.fecha || null;
delete datos.fecha;
datos.origen = 'foto';
// no persistir campos auxiliares de lectura
delete datos.tarjeta_legible;
delete datos.confianza;
delete datos.dudas;

// --- ¿falta algo crítico? repreguntar; el orquestador continúa la charla ---
const faltan = [];
if (!datos.observacion) faltan.push('*qué observaste* (contame brevemente)');
if (!datos.lugar) faltan.push('*dónde fue* (sector / locación)');

let session, reply;
if (faltan.length) {
  // dejamos el borrador en sesión: si el operario responde por texto, lo toma el orquestador
  session = { estado_flujo: 'awaiting_orchestrator', datos: { ...datos, _historial: [] } };
  reply = '📸 Recibí tu tarjeta, ¡gracias! Me falta un dato: ' + faltan.join(' y ') + '.';
} else {
  session = { estado_flujo: 'awaiting_confirm', datos };
  const lineas = [
    '📋 *Resumen de tu observación*',
    datos.fecha_obs ? `📅 Fecha: ${datos.fecha_obs}` : '📅 Fecha: (sin fecha en la tarjeta — se usa la de carga)',
    `📍 Lugar: ${datos.lugar}`,
    datos.servicio_obra ? `🏗 Servicio/Obra: ${datos.servicio_obra}` : null,
    `🏷 Tipo: ${TIPO[datos.tipo]}`,
    datos.categoria ? `📂 Categoría: ${datos.categoria} · ${CATEGORIAS[datos.categoria]}${datos.subitem ? ` (${datos.subitem})` : ''}` : null,
    `📝 ${datos.observacion}`,
    datos.acciones_correctivas ? `🛠 Acción inmediata: ${datos.acciones_correctivas}` : '🛠 Acción inmediata: (sin registrar)',
    `🚦 Prioridad: ${SEMAFORO[datos.prioridad]}`,
    // si el modelo tuvo dudas al leer, las mostramos para que el operario las verifique
    dudas.length ? '' : null,
    dudas.length ? `⚠️ Verificá esto que no leí con certeza: ${dudas.slice(0, 3).join('; ')}` : null,
    '',
    'Respondé *OK* para confirmar, o escribí lo que haya que corregir.',
  ].filter((l) => l !== null);
  reply = lineas.join('\n');
}

const persist = { reporter_hash: ctx.hash, session, reply };
if (ctx.fotoB64) {          // la foto se guarda una sola vez, al extraer
  persist.foto_base64 = ctx.fotoB64;
  persist.foto_mime = ctx.mediaType || 'image/jpeg';
}

return [{ json: { persist } }];

// Nodo "Procesar transcripción": toma la salida de Whisper (Groq) y decide:
//  - transcripción vacía o error → respuesta de fallback directa (la conversación sigue viva)
//  - transcripción OK → el texto entra al Orquestador como si el operario lo hubiera escrito
// Si el audio venía con texto (caption), se concatenan.
const ctx = $('Router').first().json;
const resp = $input.first().json;

const transcripcion = (resp && typeof resp.text === 'string') ? resp.text.trim() : '';

if (!transcripcion) {
  return [{ json: { entendido: 'no', persist: {
    reporter_hash: ctx.hash,
    reply: '🎙️😕 No pude entender el audio. ¿Podés reenviarlo (más cerca del micrófono) o escribirlo en un mensaje?',
  } } }];
}

const caption = (ctx.text || '').trim();
const texto = caption ? `${caption}\n${transcripcion}` : transcripcion;

return [{ json: { ...ctx, text: texto, transcripcion, entendido: 'si' } }];

// Nodo "Adjuntar foto": la observación ya tiene folio y el operario mandó una foto
// dentro de la ventana de adjuntos. Se agrega como evidencia y se renueva la ventana.
const ctx = $('Router').first().json;
const info = (ctx.session && ctx.session.datos) || {};

let buf = null;
try { buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (e) { /* descarga fallida */ }
if (!buf) {
  return [{ json: { persist: {
    reporter_hash: ctx.hash,
    session: { estado_flujo: 'awaiting_photos', datos: info }, // la ventana sigue abierta
    reply: '😕 No pude descargar esa foto. ¿La reenviás?',
  } } }];
}
const n = (Number(info.fotos_count) || 0) + 1;

return [{ json: { persist: {
  reporter_hash: ctx.hash,
  foto_base64: buf.toString('base64'),
  foto_mime: ctx.mediaType || 'image/jpeg',
  foto_para: info.observacion_id,
  session: { estado_flujo: 'awaiting_photos', datos: { ...info, fotos_count: n } },
  reply: `📎 Foto ${n} agregada al folio *${info.folio || ''}*. Mandá más si querés, o seguí con lo tuyo. 👍`,
} } }];

// Nodo "Procesar orquestador": interpreta la decisión del LLM (preguntar/confirmar/rechazar),
// arma la respuesta al operario, actualiza la sesión con el historial y prepara la persistencia.
const ctx = $('Orquestador').first().json;

const CATEGORIAS = {
  1: 'Reacciones de las Personas', 2: 'Posiciones de las Personas',
  3: 'Equipos de Protección Personal', 4: 'Herramientas y Equipos',
  5: 'Procedimientos', 6: 'Orden y Aseo', 7: 'Vehicular', 8: 'Ambiente',
  9: 'Productos Químicos', 10: 'Instalaciones', 11: 'Otros',
};
const TIPO = { inseguro: 'Acto Inseguro', seguro: 'Acto Seguro', no_audita: 'No Audita' };
const SEMAFORO = { rojo: '🔴 Crítica', amarillo: '🟡 Atención', verde: '🟢 Leve' };

// --- parsear salida del LLM (tolerante a fences / respuesta inválida) ---
let out = null;
try {
  const content = $input.first().json.choices[0].message.content;
  out = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch (e) { /* LLM caído o JSON inválido */ }

if (!out || !out.accion) {
  return [{ json: { persist: {
    reporter_hash: ctx.hash,
    reply: '😕 Se me complicó procesar tu mensaje. Probá de nuevo en unos segundos, o entregá la tarjeta en papel como siempre.',
  } } }];
}

// --- fusionar datos: lo previo + lo nuevo (lo nuevo pisa) ---
const datos = { ...(ctx.datosPrevios || {}), ...(out.datos || {}) };

// normalizaciones defensivas
datos.tipo = ['inseguro', 'seguro', 'no_audita'].includes(datos.tipo) ? datos.tipo : 'inseguro';
datos.severidad = Math.min(4, Math.max(1, Number(datos.severidad) || 1));
const cat = Number(datos.categoria);
datos.categoria = cat >= 1 && cat <= 11 ? cat : null;
const np = Number(datos.num_personas);
datos.num_personas = Number.isFinite(np) && np > 0 ? Math.round(np) : null;
// prioridad determinística (no se delega al LLM)
datos.prioridad = datos.tipo === 'seguro' ? 'verde'
  : datos.severidad >= 3 ? 'rojo'
  : datos.severidad === 2 ? 'amarillo' : 'verde';

// metadata de Twilio
if (ctx.twilioTimestamp) datos.timestamp_mensaje = ctx.twilioTimestamp;
if (ctx.latitud != null) datos.latitud = ctx.latitud;
if (ctx.longitud != null) datos.longitud = ctx.longitud;

// --- actualizar historial de la conversación ---
const historial = Array.isArray(ctx.historial) ? [...ctx.historial] : [];
historial.push({ role: 'user', content: ctx.text || '' });
historial.push({ role: 'assistant', content: out.mensaje || '' });
// acotar historial para no crecer indefinidamente
while (historial.length > 12) historial.shift();

let reply, session, flag = null;

if (out.accion === 'rechazar') {
  // contenido no válido: cerrar sesión, registrar el strike y avisar según reincidencia.
  // {{AVISO_RECHAZO}} se resuelve DESPUÉS de persistir, cuando la API devuelve el contador
  // (2º rechazo: advertencia; 3º: pausa de 30 min con hora). Nunca silencio.
  reply = (out.mensaje ||
    '😊 Esto no parece una observación de seguridad. Si necesitás ayuda, hablá con tu supervisor de HSE.') +
    '{{AVISO_RECHAZO}}';
  session = null;
  flag = { razon: 'contenido_dudoso' };
} else if (out.accion === 'confirmar') {
  // tenemos lo esencial: armar resumen determinístico y pedir OK
  // red de seguridad: nunca confirmar "sin categoría"
  if (!datos.categoria) datos.categoria = 11; // Otros
  // defaults acordados: nunca más blancos mudos en el export
  const tz = $env.GENERIC_TIMEZONE || 'America/Argentina/Buenos_Aires';
  const ahoraLocal = new Date().toLocaleString('sv-SE', { timeZone: tz }).slice(0, 16); // YYYY-MM-DD HH:MM
  if (!datos.fecha_obs || /^ahora$/i.test(String(datos.fecha_obs).trim())) datos.fecha_obs = ahoraLocal;
  if (!datos.servicio_obra) datos.servicio_obra = 'No indicado';
  if (!datos.acciones_correctivas) datos.acciones_correctivas = 'Sin acciones en el momento';
  const PERSONAL = { propio: 'propio', contratista: 'contratista' };
  const lineas = [
    '📋 *Resumen de tu observación*',
    `📅 Fecha: ${datos.fecha_obs}`,
    `📍 Lugar: ${datos.lugar || '(sin especificar)'}`,
    `🏗 Servicio/Obra: ${datos.servicio_obra}`,
    `🏷 Tipo: ${TIPO[datos.tipo]}`,
    datos.categoria ? `📂 Categoría: ${datos.categoria} · ${CATEGORIAS[datos.categoria]}${datos.subitem ? ` (${datos.subitem})` : ''}` : null,
    datos.num_personas ? `👥 Personas: ${datos.num_personas}${PERSONAL[datos.personal] ? ` (${PERSONAL[datos.personal]})` : ''}` : null,
    `📝 ${datos.observacion || '(sin descripción)'}`,
    `🛠 Acción inmediata: ${datos.acciones_correctivas}`,
    `🚦 Prioridad: ${SEMAFORO[datos.prioridad]}`,
    '',
    'Respondé *OK* para confirmar, o escribí lo que haya que corregir.',
  ].filter((l) => l !== null);
  reply = lineas.join('\n');
  session = { estado_flujo: 'awaiting_confirm', datos: { ...datos, _historial: historial } };
} else {
  // preguntar: seguimos recolectando
  reply = out.mensaje || '¿Me contás un poco más?';
  session = { estado_flujo: 'awaiting_orchestrator', datos: { ...datos, _historial: historial } };
}

// eco de la transcripción: el operario ve qué se entendió y puede corregir antes del OK
if (ctx.transcripcion) {
  const t = ctx.transcripcion.length > 250 ? ctx.transcripcion.slice(0, 250) + '…' : ctx.transcripcion;
  reply = `🎙️ Escuché: «${t}»\n\n${reply}`;
}

const persist = { reporter_hash: ctx.hash, session, reply };
if (flag) persist.flag = flag;
return [{ json: { persist } }];

// Nodo "Finalizar observación": el operador confirmó el resumen.
// El borrador de la sesión se convierte en observación definitiva (la API devuelve el folio).
const ctx = $input.first().json;
const datos = { ...((ctx.session && ctx.session.datos) || {}) };
delete datos._historial; // el historial de chat no se persiste en la observación

// Red de seguridad (cubre también el flujo foto, que no pasa por el orquestador):
// nunca guardar fecha ni servicio en blanco.
const tz = $env.GENERIC_TIMEZONE || 'America/Argentina/Buenos_Aires';
const ahoraLocal = new Date().toLocaleString('sv-SE', { timeZone: tz }).slice(0, 16);
if (!datos.fecha_obs || /^ahora$/i.test(String(datos.fecha_obs).trim())) datos.fecha_obs = ahoraLocal;
if (!datos.servicio_obra) datos.servicio_obra = 'No indicado';

return [{ json: { persist: {
  reporter_hash: ctx.hash,
  observacion: { ...datos, canal: 'whatsapp', raw_llm_json: JSON.stringify(datos) },
  // la API abre la ventana de adjuntos con el folio recién asignado (10 min)
  session: 'awaiting_photos',
  reply: '✅ ¡Listo! Tu observación quedó registrada con el folio *{{FOLIO}}*.\n\n' +
    '📎 Si tenés *fotos de lo observado* (el equipo, el lugar, la tarjeta), mandámelas ahora y las adjunto al reporte.\n\n' +
    'El equipo de HSE ya la puede ver en el tablero. Gracias por sumar a la seguridad de todos. 👷‍♂️',
} } }];

// Nodo "Armar respuesta saliente": el webhook ya devolvió un ACK vacío a Twilio
// (así jamás hay silencio por timeout); acá se arma el mensaje real que sale por
// la API REST. Resuelve los placeholders {{FOLIO}} y {{AVISO_RECHAZO}} con lo que
// devolvió la persistencia.
const r = $input.first().json;             // respuesta de "Persistir"
const ctx = $('Preparar contexto').first().json;

let texto = r.reply || '🙏 ¡Gracias! Recibimos tu mensaje.';
if (r.folio) texto = texto.split('{{FOLIO}}').join(r.folio);

// aviso progresivo de rechazo: nada (1º) → advertencia (2º) → pausa informada (3º)
let aviso = '';
if (r.flag) {
  const tz = $env.GENERIC_TIMEZONE || 'America/Argentina/Buenos_Aires';
  if (r.flag.bloqueado) {
    const hora = r.flag.desbloqueado_en
      ? new Date(String(r.flag.desbloqueado_en).replace(' ', 'T') + 'Z')
          .toLocaleTimeString('es-AR', { timeZone: tz, hour: '2-digit', minute: '2-digit', hour12: false })
      : '';
    aviso = `\n\n🚫 *Pausé la recepción de tus reportes${hora ? ` hasta las ${hora}` : ' por 30 minutos'}*: los últimos mensajes no parecen observaciones de seguridad. El canal funciona bien — después de esa hora podés volver a reportar. Si esto es un error, hablá con tu supervisor de HSE.`;
  } else if (r.flag.rechazos >= 2) {
    aviso = '\n\n⚠️ Ojo: si el próximo mensaje tampoco es una observación de seguridad real, voy a pausar tus reportes por 30 minutos.';
  }
}
texto = texto.split('{{AVISO_RECHAZO}}').join(aviso);

return [{ json: {
  to: ctx.to,               // el número del operario, solo en tránsito — no se persiste
  fromBot: ctx.fromBot,     // el número del sandbox/bot
  auth: ctx.twilioAuth,
  texto,
} }];
